import{_ as i,c as t,o as a,ae as l}from"./chunks/framework.BHrE6nLq.js";const d=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"Picstome","text":"Free Open Source Tools for Photographers","tagline":"Self-Hosted | Secure | Efficient","image":{"src":"/assets/landing-hero.jpg","alt":"Picstome"},"actions":[{"theme":"brand","text":"Coming Soon","link":"/install/"},{"theme":"alt","text":"View on GitHub","link":"https://github.com/picstome"}]},"features":[{"icon":"📸","title":"Gallery Management","details":"Create galleries, upload images in original or resized versions, and share them securely with your clients."},{"icon":"📝","title":"Contract Management","details":"Generate contracts, handle online signatures, and manage the complete contract lifecycle with ease."},{"icon":"👥","title":"Client Relationship","details":"Comprehensive CRM with client profiles, activity tracking, and third-party integrations."},{"icon":"🚀","title":"Easy Deployment","details":"Self-hosted solution with minimal requirements (2 cores, 512MB RAM, 10GB SSD)."},{"icon":"🔒","title":"Secure & Private","details":"You control your data with flexible storage options including local storage and S3 integration."},{"icon":"🌍","title":"Multilingual","details":"Support multiple languages and translate your interface to reach a global audience."}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),o={name:"index.md"};function n(r,e,s,c,h,m){return a(),t("div",null,e[0]||(e[0]=[l('<div class="vp-doc"><h2 id="why-choose-picstome" tabindex="-1">Why Choose Picstome? <a class="header-anchor" href="#why-choose-picstome" aria-label="Permalink to &quot;Why Choose Picstome?&quot;">​</a></h2><p>At Picstome, we&#39;re dedicated to making your photography workflow smoother and more efficient. We&#39;re not just another backup service—we&#39;re a complete solution designed for photographers by photographers.</p><h2 id="full-feature-set" tabindex="-1">Full Feature Set <a class="header-anchor" href="#full-feature-set" aria-label="Permalink to &quot;Full Feature Set&quot;">​</a></h2><h3 id="gallery-features" tabindex="-1">Gallery Features <a class="header-anchor" href="#gallery-features" aria-label="Permalink to &quot;Gallery Features&quot;">​</a></h3><ul><li>Create and manage unlimited galleries</li><li>Upload original or optimized images</li><li>Link galleries to photoshoots</li><li>Secure public gallery sharing</li><li>Client photo proofing</li><li>Password protection</li><li>Watermark capabilities</li><li>Individual or full gallery downloads</li></ul><h3 id="photoshoot-management" tabindex="-1">Photoshoot Management <a class="header-anchor" href="#photoshoot-management" aria-label="Permalink to &quot;Photoshoot Management&quot;">​</a></h3><ul><li>Comprehensive shooting organization</li><li>Client assignment</li><li>Date and location tracking</li><li>Pricing management</li><li>Detailed notes</li><li>Gallery integration</li></ul><h3 id="contract-system" tabindex="-1">Contract System <a class="header-anchor" href="#contract-system" aria-label="Permalink to &quot;Contract System&quot;">​</a></h3><ul><li>Reusable contract templates</li><li>Multiple signature support</li><li>Automatic PDF generation</li><li>Online signing process</li><li>Private signing URLs</li><li>Full contract lifecycle</li><li>Shooting integration</li></ul><h3 id="client-management-crm" tabindex="-1">Client Management (CRM) <a class="header-anchor" href="#client-management-crm" aria-label="Permalink to &quot;Client Management (CRM)&quot;">​</a></h3><ul><li>Detailed client profiles</li><li>Contract tracking</li><li>Photoshoot history</li><li>Gallery access management</li><li>Financial statistics</li><li>Engagement metrics</li><li>Mailchimp &amp; Acumbamail integration</li></ul><h3 id="technical-specifications" tabindex="-1">Technical Specifications <a class="header-anchor" href="#technical-specifications" aria-label="Permalink to &quot;Technical Specifications&quot;">​</a></h3><ul><li>Built with PHP &amp; Laravel 11</li><li>SQLite database</li><li>Single file installation</li><li>Minimal VPS requirements</li><li>Local or S3 storage options</li><li>Full multilingual support</li></ul></div>',1)]))}const g=i(o,[["render",n]]);export{d as __pageData,g as default};
